--- a/packages/ui/src/engine/pixel-characters.ts
+++ b/packages/ui/src/engine/pixel-characters.ts
@@ -3326,6 +3326,64 @@
+/**
+ * Draw a minimap overview panel in the corner of the screen.
+ * Shows all rooms as colored rectangles scaled to fit,
+ * with character positions as dots.
+ * Highlights the currently viewed room with a border.
+ * @param ctx CanvasRenderingContext2D
+ * @param rooms Array of Room objects with layout positions and sizes
+ * @param characters Array of characters with positions and types: { id, type, x, y, roomId }
+ * @param currentRoomId The id of the currently viewed room
+ * @param panelX X coordinate of minimap panel top-left corner
+ * @param panelY Y coordinate of minimap panel top-left corner
+ * @param panelWidth Width of minimap panel
+ * @param panelHeight Height of minimap panel
+ */
+export function drawMinimap(
+  ctx: CanvasRenderingContext2D,
+  rooms: Room[],
+  characters: { id: string; type: CharacterType; x: number; y: number; roomId: string }[],
+  currentRoomId: string | null,
+  panelX: number,
+  panelY: number,
+  panelWidth: number,
+  panelHeight: number,
+) {
+  if (rooms.length === 0) return;
+
+  // Determine bounding box of all rooms
+  let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
+  for (const room of rooms) {
+    if (room.x < minX) minX = room.x;
+    if (room.y < minY) minY = room.y;
+    if (room.x + room.w > maxX) maxX = room.x + room.w;
+    if (room.y + room.h > maxY) maxY = room.y + room.h;
+  }
+
+  const layoutWidth = maxX - minX;
+  const layoutHeight = maxY - minY;
+  if (layoutWidth <= 0 || layoutHeight <= 0) return;
+
+  // Compute scale to fit all rooms inside panel with margin
+  const margin = 4;
+  const scaleX = (panelWidth - margin * 2) / layoutWidth;
+  const scaleY = (panelHeight - margin * 2) / layoutHeight;
+  const scale = Math.min(scaleX, scaleY);
+
+  // Background panel
+  ctx.save();
+  ctx.fillStyle = 'rgba(20, 20, 20, 0.8)';
+  ctx.fillRect(panelX, panelY, panelWidth, panelHeight);
+  ctx.strokeStyle = '#888888';
+  ctx.lineWidth = 1;
+  ctx.strokeRect(panelX, panelY, panelWidth, panelHeight);
+
+  // Draw rooms as rectangles
+  for (const room of rooms) {
+    const rx = panelX + margin + (room.x - minX) * scale;
+    const ry = panelY + margin + (room.y - minY) * scale;
+    const rw = room.w * scale;
+    const rh = room.h * scale;
+
+    // Room fill color based on type (lighter version)
+    const baseColors: Record<CharacterType, string> = {
+      king: '#cc4444', nobility: '#7755cc', knight: '#336699', squire: '#228833',
+      healer: '#2e8b57', sentinel: '#8b4513', scribe: '#5555aa', judge: '#aa4444', blacksmith: '#666666',
+    };
+    const fillColor = baseColors[room.type] || '#555555';
+    ctx.fillStyle = fillColor;
+    ctx.fillRect(rx, ry, rw, rh);
+
+    // Highlight current room with border
+    if (currentRoomId === room.id) {
+      ctx.strokeStyle = '#ffff00';
+      ctx.lineWidth = 2;
+      ctx.strokeRect(rx - 1, ry - 1, rw + 2, rh + 2);
+    } else {
+      ctx.strokeStyle = '#222222';
+      ctx.lineWidth = 1;
+      ctx.strokeRect(rx, ry, rw, rh);
+    }
+  }
+
+  // Draw characters as dots inside their rooms
+  for (const char of characters) {
+    const room = rooms.find(r => r.id === char.roomId);
+    if (!room) continue;
+    const cx = panelX + margin + (room.x - minX) * scale + (char.x - room.x) * scale;
+    const cy = panelY + margin + (room.y - minY) * scale + (char.y - room.y) * scale;
+    const radius = 2;
+    const charColors: Record<CharacterType, string> = {
+      king: '#ffcc00', nobility: '#aa88ff', knight: '#6699cc', squire: '#44aa44',
+      healer: '#55cc88', sentinel: '#cc8855', scribe: '#8888cc', judge: '#cc6666', blacksmith: '#999999',
+    };
+    ctx.fillStyle = charColors[char.type] || '#cccccc';
+    ctx.beginPath();
+    ctx.ellipse(cx, cy, radius, radius, 0, 0, Math.PI * 2);
+    ctx.fill();
+  }
+
+  ctx.restore();
+}
+
